"""
MABE Bootstrap: Complete Optical Physics — All Extensions

Run: python3 bootstrap_optical_all.py

Prereqs: optical/ M1-M9 (from 0001_optical_module.patch)
         pip install miepython scipy

Creates 12 files:
  optical/multiple_scattering.py    — M6b: MS correction + absolute R
  optical/base_layer.py             — Primer/functionalization layers
  optical/janus_sphere.py           — Two-way color
  optical/inverse_design.py         — M11: scipy inverse design
  optical/click_linker.py           — M10: material-specific click chains
  optical/responsive_color.py       — 5 stimulus-responsive mechanisms
  optical/application_optics.py     — Application scenarios:
    Coating geometry: bulk_film / thin_film / monolayer / sparse
    Viewing: specular vs Lambertian angle averaging
    Transmission: T(lambda) for glass, complementary colors
    Substrates: 8 fabric types + arbitrary measured R(lambda)
    Shortcuts: glass_film(), textile_dipcoat(), beads_on_glass(), beads_on_textile()
  + 5 test files (139 optical tests total)

Total optical: 139 tests, 0 failed
"""
import base64, pathlib

FILES = {
    "optical/multiple_scattering.py": "",
    "optical/base_layer.py": "",
    "optical/janus_sphere.py": "",
    "optical/inverse_design.py": "",
    "optical/click_linker.py": "",
    "optical/responsive_color.py": "",
    "optical/application_optics.py": "",
    "tests/test_optical/test_extended_optics.py": "",
    "tests/test_optical/test_inverse_design.py": "",
    "tests/test_optical/test_click_linker.py": "",
    "tests/test_optical/test_responsive_color.py": "",
    "tests/test_optical/test_application_optics.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_optical/ -v")

if __name__ == "__main__":
    main()